import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"破军圣诞","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/破军圣诞.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/破军圣诞.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/破军圣诞.md"};function p(b,e,l,_,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"破军圣诞",tabindex:"-1"},[s("破军圣诞 "),r("a",{class:"header-anchor",href:"#破军圣诞","aria-label":'Permalink to "破军圣诞"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),o('<h1 id="破军圣诞-1" tabindex="-1">破军圣诞 <a class="header-anchor" href="#破军圣诞-1" aria-label="Permalink to &quot;破军圣诞&quot;">​</a></h1><p>破军圣诞<br> B+2000<br> 武器<br> 武器伤害：19L<br> 分类：戟<br> 特性：双手，长柄，格挡2<br> 体积：5</p><p>“叮叮当，叮叮当，铃儿响叮当~”<br> 这是一柄形如圣诞树的长戟，棕色的树干与翠绿的枝叶上挂满了铃铛与彩带，挥动时会发出清脆悦耳的节日铃声。</p><p>【圣诞礼物】<br> “乖孩子有礼物哦！”<br> 破军圣诞的铃铛内蕴藏着一个约100立方米的折叠空间，其中一部分为空，另一部分则装满了包装好的礼物。取出或存放物品需要一个花招动作，该空间被视为一个C级储存空间。<br> 但礼物不一样，你可以以一个自由动作从中取出一份礼物，赠予15米范围内的多个目标，但不包括自己，毕竟哪有圣诞老人送自己礼物的。<br> 收到礼物的人不会知晓礼物内容——事实上，就连你在赠送前也无法知晓。在送出礼物前，你需要进行一次d2判定，并根据结果决定礼物的内容：</p><p>· 若结果为1，目标获得一块糖果。服用后可获得“快速治疗2”效果（24点医疗点），持续一轮，并且当天无需饮食。<br> · 若结果为2，目标获得一颗苹果。服用后可获得“异常点治疗1”效果（24点医疗点），持续一轮，并且当天无需饮食。<br> 同一目标在一轮内无法同时获得两种不同的礼物效果。</p><p>【圣夜星陨】<br> “孩子们别怕，圣诞老人来了。”<br> 作为带来礼物的象征，你获得一点机运骰加值。你可以在战斗外选择一个方向将破军圣诞掷出，随后这一武器将会如同流星一般消失在天际，该武器至多向目标方向飞行5000公里，这需要花费10分钟-1小时的时间。当飞行结束后破军圣诞会如同真正的圣诞树般稳稳插在落点，并自动开始播放欢快的圣诞乐曲。<br> 当破军圣诞落地后你可以花费10分钟-1小时不等的时间蓄力跳跃，如同流星划破天空，以经典的美式超级英雄姿态精准地降落在破军圣诞的旁边。此效果视为一个B级传送类旅行效果。<br> 一切都是为了更好的送礼物。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(d,[["render",p]]);export{f as __pageData,m as default};
